class ReplayBuffer:
 def __init__(self, capacity=10000):
 self.buffer = []
 self.capacity = capacity

 def add(self, state, action, next_state):
 if len(self.buffer) >= self.capacity:
 self.buffer.pop(0)
 self.buffer.append((state, action, next_state))

 def sample(self, batch_size):
